import React, { useEffect, useState } from 'react';
import api from '../api';

const DoctorList = () => {
  const [doctors, setDoctors] = useState<any[]>([]);
  const [fName, setFName] = useState('');
  const [lName, setLName] = useState('');
  const [spec, setSpec] = useState('');
  const [email, setEmail] = useState('');

  // Edit States
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editFName, setEditFName] = useState('');
  const [editLName, setEditLName] = useState('');

  const fetchDoctors = () => {
    api.get('doctors/').then((res: any) => setDoctors(res.data));
  };

  useEffect(() => { fetchDoctors(); }, []);

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await api.post('doctors/', { 
        first_name: fName, last_name: lName, specialization: spec, email: email 
      });
      setFName(''); setLName(''); setSpec(''); setEmail('');
      fetchDoctors();
    } catch (err: any) { console.error(err.response?.data); }
  };

  const handleUpdate = async (id: number) => {
    await api.put(`doctors/${id}/`, { 
      first_name: editFName, last_name: editLName, specialization: spec, email: email 
    });
    setEditingId(null);
    fetchDoctors();
  };

  return (
    <div className="space-y-4">
      <form onSubmit={handleAdd} className="grid grid-cols-2 md:grid-cols-5 gap-2 bg-blue-50 p-4 rounded-lg">
        <input className="border p-2 rounded" placeholder="First Name" value={fName} onChange={e => setFName(e.target.value)} required />
        <input className="border p-2 rounded" placeholder="Last Name" value={lName} onChange={e => setLName(e.target.value)} required />
        <input className="border p-2 rounded" placeholder="Spec" value={spec} onChange={e => setSpec(e.target.value)} required />
        <input className="border p-2 rounded" type="email" placeholder="Email" value={email} onChange={e => setEmail(e.target.value)} required />
        <button type="submit" className="bg-blue-600 text-white rounded">Add Doctor</button>
      </form>

      <table className="min-w-full bg-white border">
        <thead className="bg-blue-600 text-white">
          <tr><th>Name</th><th>Actions</th></tr>
        </thead>
        <tbody>
          {doctors.map((d: any) => (
            <tr key={d.doctor_id} className="border-b">
              {editingId === d.doctor_id ? (
                <>
                  <td><input className="border p-1" value={editFName} onChange={e => setEditFName(e.target.value)} /></td>
                  <td className="text-center">
                    <button onClick={() => handleUpdate(d.doctor_id)} className="text-green-600">Save</button>
                  </td>
                </>
              ) : (
                <>
                  <td className="p-2">Dr. {d.first_name} {d.lName}</td>
                  <td className="p-2 text-center space-x-2">
                    <button onClick={() => { setEditingId(d.doctor_id); setEditFName(d.first_name); }} className="text-blue-600">Edit</button>
                    <button onClick={() => api.delete(`doctors/${d.doctor_id}/`).then(fetchDoctors)} className="text-red-600">Delete</button>
                  </td>
                </>
              )}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default DoctorList;
